@startuml
title netnotes

class "User" {
  [C]
  String name
  String email
}

class "Shelf" {
  [C]
  String name
}

class "Note" {
  [C]
  String title
  String body
}

class "Article" {
  [C]
  String title
  String url
}

class "Tag" {
  [C]
  String body
}

User --> User : follows
User --> Shelf : creates
User --> Shelf : likes
User --> Note : creates
User --> Note : likes
User --> Article : finds
User --> Article : likes
User --> Tag : follows

Shelf o-- Note : contains
Shelf o-- Article : contains

Note *-- Tag : attaches
Article *-- Tag : attaches

@enduml
